const norm = s => (s || '').toString().toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/\b(sa|sas|sarl|sasu|eurl|group|groupe|holding|france|se)\b/g, ' ').replace(/[^a-z0-9]+/g, ' ').replace(/\s+/g, ' ').trim();
const slug = u => { const m = (u || '').toString().toLowerCase().match(/linkedin\.com\/company\/([^\/?#]+)/); return m ? m[1] : ''; };
const companies = $input.all().map(it => it.json);
const cibles = $('Airtable : Comptes Cibles').all().map(it => it.json);
const byName = new Map(), bySlug = new Map(), bySiren = new Map();
for (const c of companies) { const n = norm(c['Company Name']); if (n) byName.set(n, c); const s = slug(c['Linkedin Url']); if (s) bySlug.set(s, c); const si = (c['SIREN'] || '').toString().replace(/\D/g, ''); if (si) bySiren.set(si, c); }
const out = [];
for (const cb of cibles) {
  if ((cb['Qualif IA'] || '') !== 'Client final') continue;
  const name = (cb.Entreprise || '').toString().trim();
  if (!name) continue;
  const siren = (cb['SIREN / SIRET'] || '').toString().replace(/\D/g, '');
  const linkedin = (cb['Page LinkedIn entreprise'] || '').toString().trim();
  const cslug = slug(linkedin);
  const villeRaw = (cb.Ville || '').toString().trim();
  const ville = (villeRaw && !/^\d{1,3}$/.test(villeRaw) && villeRaw.toLowerCase() !== 'autre') ? villeRaw : '';
  let match = null;
  if (siren && bySiren.has(siren)) match = bySiren.get(siren);
  else if (byName.has(norm(name))) match = byName.get(norm(name));
  else if (cslug && bySlug.has(cslug)) match = bySlug.get(cslug);
  if (match) {
    const fields = {};
    if (siren && !((match['SIREN'] || '').toString().trim())) fields['SIREN'] = siren;
    if (linkedin && !((match['Linkedin Url'] || '').toString().trim())) fields['Linkedin Url'] = linkedin;
    if (ville && !((match['Headquarters Location'] || '').toString().trim())) fields['Headquarters Location'] = ville;
    if (Object.keys(fields).length === 0) continue;
    fields.id = match.id;
    out.push({ json: fields });
  } else {
    const fields = { 'Company Name': name };
    if (siren) fields['SIREN'] = siren;
    if (linkedin) fields['Linkedin Url'] = linkedin;
    if (ville) fields['Headquarters Location'] = ville;
    out.push({ json: fields });
  }
}
return out;
